"""AI 服务：接入 LLM 辅助剧本生成"""
import json
from typing import Optional


class AIService:
    """AI 写作辅助服务"""

    def __init__(self, api_key: str = "", base_url: str = "", model: str = ""):
        self.api_key = api_key
        self.base_url = base_url
        self.model = model
        self._client = None

    @property
    def ready(self) -> bool:
        return bool(self.api_key)

    def _get_client(self):
        if self._client is None and self.ready:
            from openai import OpenAI
            kwargs = {"api_key": self.api_key}
            if self.base_url:
                kwargs["base_url"] = self.base_url
            self._client = OpenAI(**kwargs)
        return self._client

    def _call_llm(self, messages, temperature=0.8) -> Optional[str]:
        client = self._get_client()
        if not client:
            return None
        try:
            resp = client.chat.completions.create(
                model=self.model or "gpt-4o-mini",
                messages=messages,
                temperature=temperature,
            )
            return resp.choices[0].message.content
        except Exception as e:
            return f"[AI 调用失败] {str(e)}"

    # ----- 以下为剧本辅助功能 -----

    def generate_outline(self, genre: str, theme: str, num_chapters: int = 5) -> Optional[str]:
        """生成故事大纲"""
        prompt = f"""你是一个专业漫画编剧。请为以下设定创作一个动态漫画故事大纲。

类型：{genre}
主题：{theme}
章节数：{num_chapters}

请按以下格式输出：
## 故事简介
（200字内）

## 章节大纲
第1章 - [标题]：[概要]
第2章 - [标题]：[概要]
...

每个章节 100字左右概要。"""

        return self._call_llm([
            {"role": "system", "content": "你是专业漫画编剧，擅长创作引人入胜的剧情。"},
            {"role": "user", "content": prompt}
        ])

    def generate_chapter_script(self, chapter_title: str, chapter_summary: str,
                                characters: list, num_scenes: int = 5) -> Optional[str]:
        """根据章节大纲生成详细剧本"""
        char_desc = "\n".join([f"- {c['name']}：{c.get('personality', '')}" for c in characters])
        prompt = f"""请根据以下章节概要，生成该章节的详细剧本，共 {num_scenes} 场。

章节标题：{chapter_title}
章节概要：{chapter_summary}

登场角色：
{char_desc}

每场包含：
- 场景标题
- 地点/时间
- 剧情概要
- 3-5 个分镜画面描述（含镜头语言）
- 角色对话（含语气标注）

请用 JSON 数组格式输出：
[{{"title":"第一场","location":"...","time":"...","summary":"...",
   "panels":[{{"description":"...","camera":"...","dialogue":[{{"speaker":"...","content":"...","emotion":"..."}}]}}]}}]"""

        return self._call_llm([
            {"role": "system", "content": "你是专业漫画分镜师，输出严格 JSON 格式。"},
            {"role": "user", "content": prompt}
        ], temperature=0.7)

    def generate_dialogue(self, scene_summary: str, characters: list, num_lines: int = 8) -> Optional[str]:
        """为场景生成对话"""
        char_desc = "\n".join([f"- {c['name']}：{c.get('personality', '')}" for c in characters])
        prompt = f"""请为以下场景创作 {num_lines} 句角色对话。

场景概要：{scene_summary}

角色：
{char_desc}

要求：
- 对话要符合角色性格
- 标注语气/情感
- 可加入动作描述

请用 JSON 数组格式输出：
[{{"speaker":"角色名","content":"对话内容","emotion":"语气","action":"动作"}}]"""

        return self._call_llm([
            {"role": "system", "content": "你是专业漫画对白编剧，输出严格 JSON 格式。"},
            {"role": "user", "content": prompt}
        ], temperature=0.8)

    def optimize_prompt(self, panel_description: str, character_info: list = None) -> Optional[str]:
        """将分镜描述优化为 AI 生图提示词"""
        char_part = ""
        if character_info:
            char_part = "角色形象：\n" + "\n".join(
                [f"- {c['name']}：{c.get('appearance', '')}" for c in character_info]
            )
        prompt = f"""请将以下漫画分镜描述，转化为可用于 AI 绘图工具（如 Midjourney / Stable Diffusion）的生图提示词。

分镜描述：{panel_description}

{char_part}
要求：
- 输出英文提示词
- 包含画风关键词（日式漫画/动态漫画风格）
- 包含构图和视角信息
- 输出格式：正面提示词 | 负面提示词"""

        return self._call_llm([
            {"role": "system", "content": "你是 AI 绘画提示词工程师，擅长将文字描述转化为高质量绘图提示词。"},
            {"role": "user", "content": prompt}
        ], temperature=0.6)
